export async function markAttemptStarted(
	client: Client,
	input: AttemptStartInput,
): Promise<AttemptTransitionResult> {
	const now = input.now ?? Date.now();
	const startedAt = input.startedAt ?? now;
	const eventId = input.eventId ?? createPrefixedId("evt");
	const tx = await client.transaction("write");

	try {
		const validation = await validateAttemptTransition(tx, input, now);

		if (!validation.ok) {
			await tx.commit();
			return validation.result;
		}

		const { run, attempt } = validation;

		if (attempt.status === "running" && run.status === "running") {
			await tx.commit();
			return {
				applied: true,
				idempotent: true,
				runStatus: "running",
				attemptStatus: "running",
				eventId: null,
				updatedAt: now,
			};
		}

		await tx.execute({
			sql: `
				UPDATE attempts
				SET
					status = ?,
					sandbox_id = COALESCE(?, sandbox_id),
					command = COALESCE(?, command),
					started_at = COALESCE(started_at, ?),
					updated_at = ?
				WHERE id = ? AND run_id = ?
			`,
			args: ["running", input.sandboxId ?? null, input.command ?? null, startedAt, now, input.attemptId, input.runId],
		});

		await tx.execute({
			sql: `
				UPDATE runs
				SET
					status = ?,
					started_at = COALESCE(started_at, ?),
					updated_at = ?
				WHERE id = ?
			`,
			args: ["running", startedAt, now, input.runId],
		});

		await insertEvent(tx, {
			id: eventId,
			runId: input.runId,
			attemptId: input.attemptId,
			level: "info",
			type: "attempt.started",
			message: "Attempt started.",
			data: {
				sandboxId: input.sandboxId ?? null,
				command: input.command ?? null,
				startedAt,
			},
			now,
		});

		await tx.commit();

		return {
			applied: true,
			idempotent: false,
			runStatus: "running",
			attemptStatus: "running",
			eventId,
			updatedAt: now,
		};
	} catch (error) {
		await tx.rollback();
		throw error;
	} finally {
		tx.close();
	}
}

